unsigned long long run_event_based_simulation(Inputs in, SimulationData SD, int mype)
{
	if( mype == 0)	printf("Running baseline event-based simulation...\n");

	int nthreads = in.nthreads;

	#pragma omp parallel num_threads(nthreads)
	{
		#pragma omp for
		for( int i = 0; i < in.lookups; i++ )
		{
			uint64_t seed = STARTING_SEED;	
			seed = fast_forward_LCG(seed, 2*i);
			double p_energy = LCG_random_double(&seed);
			int mat         = pick_mat(&seed); 

			double macro_xs_vector[5] = {0};

			calculate_macro_xs(
					p_energy,        
					mat,             
					in.n_isotopes,   
					in.n_gridpoints, 
					SD.num_nucs,     
					SD.concs,        
					SD.unionized_energy_array, 
					SD.index_grid,   
					SD.nuclide_grid, 
					SD.mats,         
					macro_xs_vector, 
					in.grid_type,    
					in.hash_bins,    
					SD.max_num_nucs  
					);

			double max = -1.0;
			int max_idx = 0;
			for(int j = 0; j < 5; j++ )
			{
				if( macro_xs_vector[j] > max )
				{
					max = macro_xs_vector[j];
					max_idx = j;
				}
			}
			SD.verification[i] = max_idx+1;
		}
	}

	if( mype == 0)	printf("Reducing verification results...\n");

	unsigned long verification_scalar = 0;
	for( int i = 0; i < in.lookups; i++ )
		verification_scalar += SD.verification[i];

	return verification_scalar;
}

unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData SD, int mype)
{
	const char * optimization_name = "Optimization 1 - basic sample/lookup kernel splitting";

	if( mype == 0)	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	if( mype == 0)	printf("Allocating additional data required by kernel...\n");
	size_t total_sz = 0;

	total_sz = in.lookups * sizeof(double) + in.lookups * sizeof(int);

	if( mype == 0)	printf("Allocated an additional %.0lf MB of data.\n", total_sz/1024.0/1024.0);

	if( mype == 0)	printf("Beginning optimized simulation...\n");

	int nthreads = in.nthreads;

	#pragma omp parallel num_threads(nthreads)
	{
		#pragma omp for
		for( int i = 0; i < in.lookups; i++ )
		{
			uint64_t seed = STARTING_SEED;	
			seed = fast_forward_LCG(seed, 2*i);
			double p_energy = LCG_random_double(&seed);
			int mat         = pick_mat(&seed); 

			SD.p_energy_samples[i] = p_energy;
			SD.mat_samples[i] = mat;
		}
	}

	#pragma omp parallel num_threads(nthreads)
	{
		#pragma omp for
		for( int i = 0; i < in.lookups; i++ )
		{
			double macro_xs_vector[5] = {0};

			calculate_macro_xs(
					SD.p_energy_samples[i],        
					SD.mat_samples[i],             
					in.n_isotopes,   
					in.n_gridpoints, 
					SD.num_nucs,     
					SD.concs,        
					SD.unionized_energy_array, 
					SD.index_grid,   
					SD.nuclide_grid, 
					SD.mats,         
					macro_xs_vector, 
					in.grid_type,    
					in.hash_bins,    
					SD.max_num_nucs  
					);

			double max = -1.0;
			int max_idx = 0;
			for(int j = 0; j < 5; j++ )
			{
				if( macro_xs_vector[j] > max )
				{
					max = macro_xs_vector[j];
					max_idx = j;
				}
			}
			SD.verification[i] = max_idx+1;
		}
	}

	if( mype == 0)	printf("Reducing verification results...\n");

	unsigned long verification_scalar = 0;
	for( int i = 0; i < in.lookups; i++ )
		verification_scalar += SD.verification[i];

	return verification_scalar;
}

int main( int argc, char* argv[] )
{
	int version = 20;
	int mype = 0;
	double omp_start, omp_end;
	int nprocs = 1;
	unsigned long long verification;

	#ifdef MPI
	MPI_Init(&argc, &argv);
	MPI_Comm_size(MPI_COMM_WORLD, &nprocs);
	MPI_Comm_rank(MPI_COMM_WORLD, &mype);
	#endif

	#ifdef AML
	aml_init(&argc, &argv);
	#endif

	Inputs in = read_CLI( argc, argv );

	#ifdef OPENMP
	omp_set_num_threads(in.nthreads); 
	#endif

	if( mype == 0 )
		print_inputs( in, nprocs, version );

	SimulationData SD;

	if( in.binary_mode == READ )
		SD = binary_read(in);
	else
		SD = grid_init_do_not_profile( in, mype );

	if( in.binary_mode == WRITE && mype == 0 )
		binary_write(in, SD);

	if( mype == 0 )
	{
		printf("\n");
		border_print();
		center_print("SIMULATION", 79);
		border_print();
	}

	omp_start = get_time();

	if( in.simulation_method == EVENT_BASED )
	{
		if( in.kernel_id == 0 )
			verification = run_event_based_simulation(in, SD, mype);
		else if( in.kernel_id == 1 )
			verification = run_event_based_simulation_optimization_1(in, SD, mype);
		else
		{
			printf("Error: No kernel ID %d found!\n", in.kernel_id);
			exit(1);
		}
	}
	else
		verification = run_history_based_simulation(in, SD, mype);

	if( mype == 0)	
	{	
		printf("\n" );
		printf("Simulation complete.\n" );
	}

	omp_end = get_time();

	verification = verification % 999983;

	int is_invalid_result = print_results( in, mype, omp_end-omp_start, nprocs, verification );

	#ifdef MPI
	MPI_Finalize();
	#endif

	#ifdef AML
	aml_finalize();
	#endif

	return is_invalid_result;
}

