int compare_by_mat(const void *a, const void *b, const void *context)
{
	const int *mat_a = (const int *)a;
	const int *mat_b = (const int *)b;
	const double *energy_a = (const double *)context + ((mat_a - (const int *)context) / sizeof(int));
	const double *energy_b = (const double *)context + ((mat_b - (const int *)context) / sizeof(int));

	if( *mat_a != *mat_b )
		return *mat_a - *mat_b;
	if( *energy_a > *energy_b )
		return 1;
	else if( *energy_a < *energy_b )
		return -1;
	else
		return 0;
}

